import { useEffect } from "react";
import { useContext } from "react";
import QueueContext from "../Contexts/QueueContext";
import DownloadZip from "../JavaScript/DownloadZip";
import MakeRequest from "../JavaScript/MakeRequest";
import Promiseify from "../JavaScript/Promiseify";
import SavePromisesToZip from "../JavaScript/SavePromisesToZip";
import "../Stylesheets/QueueDownload.css";

const QueueDownload = (props) => {
  const { queue, setQueue } = useContext(QueueContext);
  const { downloading, setDownloading } = props;

  useEffect(() => {
    if (!queue.length) {
      setDownloading(false);
    }
  }, [queue]);

  const handleClick = async () => {
    setDownloading(true);

    for (let i = 0; i < queue.length; i++) {
      const currCharacter = queue[i];
      // This runs in O(n^2), fix this !!!!
      // Creating a copy array and popping elements from it and setting state as we go didn't work,-
      // -we'll have to get creative.

      setQueue((queue) =>
        queue.filter((char) => char.name !== currCharacter.name)
      );

      const links = await MakeRequest(currCharacter.id, { galleryOnly: true });
      const promises = await Promiseify(links);
      const zip = await SavePromisesToZip(promises);
      await DownloadZip(zip, links.name);
    }
  };

  return (
    <button
      type="button"
      className="btn queue-btn btn-outline-primary fixed-bottom w-100"
      disabled={!queue.length || downloading}
      onClick={handleClick}
    >
      {downloading ? "Download in progress..." : "Start Download"}
    </button>
  );
};

export default QueueDownload;
